import type { CareerQuestion } from "./rrt-questions";

export const ptaQuestionsBatch27: CareerQuestion[] = [
  { id: "pta-b27-001", stem: "A patient with a complete T6 SCI is performing an independent sliding board transfer from bed to wheelchair. During the transfer, the patient's blood pressure drops suddenly and they become pale and diaphoretic. This is MOST likely:", options: ["Orthostatic hypotension due to loss of sympathetic vasomotor control below T6, causing blood pooling in the lower extremities upon position change", "Autonomic dysreflexia", "Normal cardiovascular response to transfer activity", "Cardiac arrest requiring CPR"], correctIndex: 0, rationale: "T6 SCI disrupts sympathetic vasomotor outflow below the injury level, preventing peripheral vasoconstriction during position changes. Blood pools in denervated lower extremity vessels, causing orthostatic hypotension (sudden BP drop, pallor, diaphoresis, dizziness). Management: gradual position changes, compression stockings, abdominal binder, tilt-table training. Autonomic dysreflexia presents with hypertension (not hypotension) in injuries at T6 and above. Normal cardiovascular response includes mild BP changes but not sudden hypotension with pallor. Cardiac arrest symptoms would include unconsciousness and absent pulse, requiring emergency response.", difficulty: 2, category: "Neurological Rehabilitation", topic: "SCI Orthostatic Hypotension" },
  { id: "pta-b27-002", stem: "A PTA is treating a patient with bilateral transtibial amputations who is learning to walk with prostheses. The patient demonstrates excessive lordosis during gait. The MOST likely cause is:", options: ["Hip flexion contractures bilaterally that tilt the pelvis anteriorly, which the patient compensates for with increased lumbar lordosis to maintain an upright posture", "Excessive prosthetic limb length", "Weak upper trapezius muscles", "Prosthetic feet set in excessive dorsiflexion"], correctIndex: 0, rationale: "Hip flexion contractures are common in transtibial amputees due to prolonged sitting and knee flexion positioning. Bilateral contractures tilt the pelvis anteriorly, causing compensatory lumbar lordosis to maintain upright posture. This is why preprosthetic contracture prevention (prone positioning, hip extension exercises) is critical. Excessive limb length causes other deviations (vaulting). Upper trapezius weakness does not cause lordosis. Excessive dorsiflexion causes knee flexion at initial contact. Treatment: hip flexor stretching (Thomas stretch, prone hip extension), core stabilization, and prosthetic alignment optimization.", difficulty: 3, category: "Prosthetics & Orthotics", topic: "Bilateral Amputee Lordosis" },
  { id: "pta-b27-003", stem: "A PTA is providing aquatic therapy to a patient with a BMI of 42 and bilateral knee osteoarthritis. The patient is immersed to the xiphoid process. Approximately what percentage of body weight is the patient bearing?", options: ["Approximately 25-35% of body weight, as xiphoid-level immersion offloads 60-75% of body weight through buoyancy", "100% of body weight (no reduction)", "0% of body weight (completely unloaded)", "90% of body weight"], correctIndex: 0, rationale: "Aquatic buoyancy progressively offloads body weight based on immersion depth: waist level (C7-xiphoid) reduces weight bearing by approximately 50%, xiphoid level by 60-75% (leaving 25-35% body weight), and shoulder level by 80-90%. For this obese patient with bilateral knee OA, xiphoid immersion allows functional exercise with dramatically reduced joint loading. At 100% body weight there would be no buoyancy effect. Complete unloading only occurs with full submersion and is impractical. 90% body weight bearing suggests minimal immersion. The buoyancy principle allows patients who cannot tolerate land-based weight-bearing exercise to perform functional activities in the pool.", difficulty: 2, category: "Therapeutic Modalities", topic: "Aquatic Buoyancy Weight Reduction" },
  { id: "pta-b27-004", stem: "A PTA is applying shortwave diathermy to a patient's hip joint. Which of the following is an ABSOLUTE contraindication?", options: ["Metal implant in the treatment field (total hip prosthesis), as shortwave diathermy can selectively heat metal components causing deep tissue burns", "Chronic osteoarthritis of the hip", "History of hip bursitis", "Being over age 50"], correctIndex: 0, rationale: "Shortwave diathermy (SWD) uses electromagnetic energy to heat deep tissues. Metal implants in the treatment field are an absolute contraindication because metal concentrates electromagnetic energy, causing selective overheating and potentially dangerous deep tissue burns around the implant. Other contraindications: pacemakers, pregnancy, malignancy, active bleeding, impaired sensation, and over the eyes or testes. Chronic OA is actually an indication for diathermy (deep heating for pain relief and increased tissue extensibility). Hip bursitis may be treated with thermal modalities. Age alone is not a contraindication. The PTA must screen for metal implants before any diathermy application.", difficulty: 2, category: "Therapeutic Modalities", topic: "Diathermy Contraindications" },
  { id: "pta-b27-005", stem: "A PTA is assessing a patient's balance reactions. When the patient is pushed backward unexpectedly, a normal equilibrium response includes:", options: ["Anterior weight shift with ankle dorsiflexion (ankle strategy), followed by hip flexion strategy if the perturbation is larger, with stepping strategy if displacement exceeds the base of support", "Falling backward with no attempt to correct balance", "Rigid freezing in place with no postural adjustment", "Extending both arms overhead"], correctIndex: 0, rationale: "Normal balance reactions to posterior perturbation follow a hierarchical strategy progression: ankle strategy (small perturbations: anterior body sway using ankle dorsiflexors as primary movers), hip strategy (moderate perturbations: rapid hip flexion shifts center of mass forward), and stepping strategy (large perturbations: taking a step forward to establish a new base of support). Falling without correction indicates absent protective reactions. Rigid freezing is abnormal and may indicate Parkinson's disease or fear of falling. Arms overhead is not a typical balance correction. Understanding this hierarchy helps the PTA design progressive balance training and identify specific strategy deficits.", difficulty: 2, category: "Biomechanics & Kinesiology", topic: "Balance Strategy Hierarchy" },
  { id: "pta-b27-006", stem: "A PTA is treating a patient with lateral epicondylalgia who also works at a computer 8 hours daily. The PTA should include which ergonomic modification in the treatment plan?", options: ["Wrist neutral positioning (avoiding sustained wrist extension), ergonomic mouse and keyboard, forearm support on the desk, and regular stretching breaks every 30-60 minutes", "Elevating the keyboard to shoulder height", "Using a standard mouse with heavy clicking resistance", "No ergonomic modifications since the condition is not work-related"], correctIndex: 0, rationale: "Lateral epicondylalgia (tennis elbow) involves the common extensor tendon. Computer work with sustained wrist extension and repetitive mouse clicking loads the wrist extensors, perpetuating the condition. Ergonomic modifications: wrist neutral position (avoiding sustained extension), ergonomic keyboard and mouse (reduce extensor activation), forearm support on the desk (reduces sustained shoulder and wrist muscle activation), and regular stretching breaks (prevent sustained loading). Elevated keyboard increases shoulder and wrist strain. Heavy mouse clicking increases extensor tendon load. Computer work is a recognized contributor to lateral epicondylalgia; ergonomic modification is part of comprehensive treatment.", difficulty: 2, category: "Patient Education & Home Programs", topic: "Lateral Epicondylalgia Ergonomics" },
  { id: "pta-b27-007", stem: "A PTA is performing a neurological screening and tests the patient's proprioception at the great toe. With eyes closed, the PTA moves the toe into dorsiflexion and asks the patient to identify the direction. The patient consistently answers incorrectly. This finding indicates:", options: ["Impaired proprioception (position sense) at the great toe, suggesting peripheral neuropathy or posterior column dysfunction, requiring communication to the supervising PT", "Normal proprioceptive function", "A visual processing problem", "Impaired motor function only"], correctIndex: 0, rationale: "Proprioception testing: the examiner moves the joint through a small excursion (dorsiflexion or plantarflexion) while the patient's eyes are closed, and the patient identifies the direction of movement. Consistent incorrect responses indicate impaired position sense. The posterior columns of the spinal cord (dorsal column-medial lemniscal pathway) carry proprioceptive information. Peripheral neuropathy (diabetes, B12 deficiency) or posterior column dysfunction (MS, B12 deficiency, tabes dorsalis) can impair proprioception. This is NOT normal. Visual processing is not tested with eyes closed. Motor function is not assessed by position sense testing. The finding should be communicated to the supervising PT for further evaluation.", difficulty: 1, category: "Data Collection & Measurement", topic: "Proprioception Testing" },
  { id: "pta-b27-008", stem: "A PTA is treating a patient with shoulder adhesive capsulitis in the 'thawing' stage. At this stage, pain is decreasing but significant stiffness remains. The MOST appropriate intervention is:", options: ["Aggressive joint mobilization (Grades III-IV) at end-range, sustained stretching, and progressive strengthening as pain allows", "Only pain management modalities with no stretching", "Complete avoidance of all shoulder movement", "Maximum resistance exercises without ROM work"], correctIndex: 0, rationale: "The thawing stage of adhesive capsulitis is characterized by decreasing pain with persistent stiffness from capsular fibrosis. This is the optimal stage for aggressive ROM interventions: Grade III-IV mobilizations at end-range stretch the fibrotic capsule, sustained stretching promotes permanent tissue elongation, and progressive strengthening rebuilds muscle function. During the freezing stage, aggressive stretching worsens inflammation. During thawing, the inflammation has subsided, making the capsule more responsive to stretching. Pain management alone without stretching misses the window for ROM recovery. Avoiding movement allows further stiffness. Strengthening without ROM work perpetuates the limitation.", difficulty: 3, category: "Musculoskeletal Rehabilitation", topic: "Adhesive Capsulitis Thawing Stage" },
  { id: "pta-b27-009", stem: "A PTA is evaluating a patient's cough effectiveness as part of pulmonary rehabilitation. An effective cough requires:", options: ["Adequate inspiratory volume (at least 60% of predicted vital capacity), sufficient expiratory muscle strength to generate high velocity airflow, and an intact glottis for pressure buildup", "Only the ability to open the mouth", "Shallow breathing with no force", "Assisted mechanical ventilation only"], correctIndex: 0, rationale: "Effective cough physiology: (1) deep inspiration (at least 60% predicted vital capacity) provides adequate lung volume behind secretions, (2) glottic closure traps air and builds intrathoracic pressure, (3) forceful expiratory muscle contraction (abdominals, intercostals) generates high-velocity airflow that shears secretions from airway walls. Patients with weak inspiratory muscles (SCI, neuromuscular disease), weak expiratory muscles, or impaired glottic function (tracheostomy) have ineffective cough. Interventions for ineffective cough: assisted cough (quad cough for SCI), mechanical insufflation-exsufflation (CoughAssist), glossopharyngeal breathing for volume augmentation. Assessment of cough effectiveness guides treatment selection.", difficulty: 2, category: "Cardiopulmonary Physical Therapy", topic: "Cough Effectiveness Assessment" },
  { id: "pta-b27-010", stem: "A PTA is measuring a patient's grip strength using a hand dynamometer. To ensure a valid measurement, the patient should:", options: ["Sit with the shoulder adducted, elbow flexed to 90°, forearm neutral, and perform 3 maximal grip efforts with the best score recorded, allowing rest between efforts", "Stand with the arm fully extended overhead", "Use only the tip of the fingers", "Squeeze as quickly as possible without maximum effort"], correctIndex: 0, rationale: "Standardized grip strength measurement (ASHT guidelines): seated position, shoulder adducted and neutrally rotated, elbow flexed 90°, forearm neutral (0° pronation/supination), wrist in 0-30° extension. Three maximal efforts are performed with adequate rest (30-60 seconds) between trials; the best (or average) of three is recorded. This standardized position ensures reliable, reproducible measurements. Standing with overhead arm changes the muscle recruitment pattern. Fingertip-only grip tests pinch, not grip strength. Submaximal effort invalidates the measurement. Grip strength norms vary by age and sex and are used to monitor rehabilitation progress, predict functional outcomes, and determine work capacity.", difficulty: 1, category: "Data Collection & Measurement", topic: "Grip Strength Measurement" },
  { id: "pta-b27-011", stem: "A PTA is treating a patient with complex regional pain syndrome who demonstrates severe allodynia (pain from non-painful stimuli). The desensitization program should progress:", options: ["From least noxious textures (silk, cotton) to progressively more textured materials (terry cloth, burlap, Velcro), with each texture applied until the patient can tolerate it before advancing", "Beginning with the most irritating stimulus possible", "Avoiding all touch to the affected area indefinitely", "Applying deep pressure massage immediately"], correctIndex: 0, rationale: "Desensitization for allodynia follows a graduated exposure approach: begin with the least noxious stimuli (silk, soft cotton) applied to the affected area until tolerance develops, then progressively introduce more textured materials (terry cloth, rice, burlap, Velcro). Each level must be tolerated before advancement. This systematic exposure normalizes the peripheral and central sensitization underlying allodynia. Starting with the most irritating stimulus causes pain, autonomic responses, and potentially worsens central sensitization. Avoiding all touch perpetuates the hypersensitivity through disuse. Deep pressure massage is too aggressive for severe allodynia. The program may take weeks to months and should be performed multiple times daily.", difficulty: 2, category: "Pain Management", topic: "CRPS Desensitization Program" },
  { id: "pta-b27-012", stem: "A PTA is treating a patient recovering from a mild traumatic brain injury (concussion) who reports persistent headaches, dizziness, and difficulty concentrating 3 weeks post-injury (post-concussion syndrome). The exercise recommendation is:", options: ["Sub-symptom threshold aerobic exercise (exercise that does not worsen symptoms), gradually progressed using the Buffalo Concussion Treadmill Test protocol", "Complete cognitive and physical rest for 6 months", "Maximum intensity exercise to 'push through' the symptoms", "Only cognitive rehabilitation with no physical activity"], correctIndex: 0, rationale: "Current evidence for post-concussion syndrome supports sub-symptom threshold aerobic exercise. The Buffalo Concussion Treadmill Test identifies the heart rate at which symptoms worsen, and exercise is prescribed at 80% of that threshold. This controlled aerobic exercise promotes neuroplasticity, cerebral blood flow regulation, and symptom resolution. Complete prolonged rest (beyond 24-48 hours) is no longer recommended as it delays recovery. Maximum intensity exercise that reproduces symptoms is counterproductive and may prolong recovery. Physical activity is an essential component of post-concussion management alongside cognitive rehabilitation. The exercise intensity is gradually increased as symptom threshold improves.", difficulty: 3, category: "Neurological Rehabilitation", topic: "Post-Concussion Exercise Protocol" },
  { id: "pta-b27-013", stem: "During iontophoresis treatment for a patient with lateral epicondylitis, the PTA uses dexamethasone (a negative ion) medication. The medication should be placed on which electrode?", options: ["The negative (cathode) electrode, because like charges repel - the negatively charged dexamethasone is driven into the tissue by the negative electrode", "The positive (anode) electrode", "Either electrode since polarity does not matter", "No electrode - the medication is applied after the electrical current"], correctIndex: 0, rationale: "Iontophoresis uses direct current to drive ionized medications through the skin. The fundamental principle: like charges repel. Dexamethasone sodium phosphate carries a negative charge (anion), so it must be placed under the negative electrode (cathode) where the negative current repels the negatively charged medication ions into the tissue. Positively charged medications (lidocaine = positive) are placed under the positive electrode (anode). Polarity absolutely matters for effective drug delivery. The medication must be applied DURING current delivery, not after. Common medications: dexamethasone (negative, anti-inflammatory), lidocaine (positive, local anesthetic), acetic acid (negative, calcium deposits).", difficulty: 2, category: "Therapeutic Modalities", topic: "Iontophoresis Electrode Polarity" },
  { id: "pta-b27-014", stem: "A PTA is working with a patient who has a unilateral neglect following a right hemisphere stroke. During functional activities, the patient consistently collides with objects on the left side and ignores food on the left side of the plate. Which intervention strategy is MOST effective?", options: ["Visual scanning training: teach the patient to systematically scan from left to right, use red anchor lines on the left side of reading material, and gradually increase task complexity", "Only present stimuli on the right side to make tasks easier", "Place an eye patch over the right eye at all times", "Provide no specific neglect training and focus only on motor recovery"], correctIndex: 0, rationale: "Unilateral neglect after right hemisphere stroke requires active scanning training. Visual scanning training teaches systematic left-to-right scanning using external cues: red anchor lines on the left margin (visual anchor), numbering the left side of plates to cue attention, and lighthouse strategy (systematic head turning). Gradual complexity increase promotes generalization. Presenting stimuli only on the right enables the neglect rather than rehabilitating it. Constant eye patching may worsen function. Motor recovery without neglect training leaves the attention deficit unaddressed, severely limiting functional independence. Prism adaptation therapy is another evidence-based approach for spatial neglect.", difficulty: 2, category: "Neurological Rehabilitation", topic: "Visual Scanning Neglect Training" },
  { id: "pta-b27-015", stem: "A PTA is evaluating the skin condition of a patient's residual limb and notices a small open area with surrounding redness on the distal tibial end. The PTA should:", options: ["Document the skin breakdown, immediately notify the supervising PT, instruct the patient to discontinue prosthetic wear until the wound heals and socket is adjusted, and refer to the prosthetist", "Ignore the skin breakdown and have the patient continue wearing the prosthesis", "Apply a bandage over the wound and resume prosthetic wear", "Increase prosthetic wear time to toughen the skin"], correctIndex: 0, rationale: "Skin breakdown on the residual limb is a significant problem requiring immediate action: document the wound (location, size, surrounding skin condition), notify the supervising PT (wound management may be needed), discontinue prosthetic wear (continued pressure prevents healing and worsens breakdown), and refer to the prosthetist (socket modification needed to address the pressure point). Ignoring breakdown leads to deeper tissue damage, infection, and potentially requires surgical revision. Bandaging over the wound and resuming prosthetic use continues the causative pressure. Increasing wear time worsens the injury. Skin integrity monitoring is a critical component of amputee rehabilitation.", difficulty: 1, category: "Prosthetics & Orthotics", topic: "Residual Limb Skin Breakdown" },
  { id: "pta-b27-016", stem: "A PTA is treating a patient with spasticity in the plantarflexors following a stroke. Before performing passive stretching of the gastrocnemius-soleus complex, the PTA applies prolonged icing to the spastic muscles. The rationale for this sequence is:", options: ["Prolonged cold application (10-15 minutes) reduces muscle spindle firing rate and decreases spasticity temporarily, making the subsequent stretch more effective and comfortable", "Cold increases spasticity making the stretch unnecessary", "Cold application has no effect on spasticity", "Cold should only be applied after stretching, never before"], correctIndex: 0, rationale: "Prolonged cold application (10-15+ minutes) reduces spasticity through: decreased muscle spindle firing rate (reduced gamma motor neuron activity), decreased nerve conduction velocity (slower reflex arc transmission), and reduced muscle contractile force. This temporary spasticity reduction creates a window of reduced resistance, allowing more effective passive stretching. Brief cold (quick ice, ice swipe) INCREASES spasticity through skin receptor stimulation. The key is prolonged application. Cold before stretching (not after) optimizes the stretch effectiveness by reducing the involuntary resistance. Other spasticity-reducing techniques before stretching: prolonged weight bearing, rhythmic rotation, slow sustained pressure.", difficulty: 3, category: "Therapeutic Modalities", topic: "Cryotherapy Spasticity Reduction" },
  { id: "pta-b27-017", stem: "A PTA is instructing a patient on a home exercise program for rotator cuff strengthening. For the external rotation exercise with a resistance band, the patient should:", options: ["Stand with the elbow flexed to 90° and held against the side, rotate the forearm outward against the band resistance while maintaining the elbow position, performing 3 sets of 10-15 reps", "Extend the arm fully and rotate the entire arm overhead", "Use maximum resistance band from the first day", "Perform the exercise lying prone with heavy weights"], correctIndex: 0, rationale: "External rotation exercise for rotator cuff strengthening: elbow flexed 90° and held at the side (eliminates deltoid contribution and isolates the infraspinatus/teres minor), forearm rotates outward against band resistance while maintaining elbow position against the trunk. 3 sets of 10-15 reps provides adequate volume for endurance and early strengthening. Full arm extension and overhead rotation changes the exercise target and may provoke impingement. Maximum resistance from day one risks re-injury. The exercise should be performed in the scapular plane when possible. Progression: increase band resistance gradually, progress to sidelying or prone positions, then functional patterns. The PTA should observe the patient perform the exercise correctly before sending home.", difficulty: 1, category: "Patient Education & Home Programs", topic: "Rotator Cuff Home Exercise" },
  { id: "pta-b27-018", stem: "A PTA is treating a patient in the ICU who has been on bed rest for 10 days following a severe illness. The patient reports feeling weak and dizzy when sitting at the edge of the bed. The PTA should implement:", options: ["A progressive mobilization protocol: head of bed elevation → seated edge of bed with vitals monitoring → standing with support → ambulation, monitoring blood pressure, heart rate, and symptoms at each progression", "Immediate ambulation at full speed without monitoring", "Continued bed rest for another 10 days", "Only upper extremity exercises with the patient supine"], correctIndex: 0, rationale: "Prolonged bed rest (10 days) causes significant cardiovascular deconditioning: plasma volume decreases 10-15%, orthostatic intolerance develops, and muscle atrophy reduces functional capacity. Progressive mobilization follows a stepwise approach: elevate head of bed incrementally, progress to seated edge of bed (dangle with vital sign monitoring), standing with support, and ambulation. Monitor blood pressure (orthostatic hypotension: SBP drop >20 mmHg), heart rate (excessive tachycardia >20 bpm increase), and symptoms (dizziness, nausea, diaphoresis) at each transition. Immediate ambulation risks syncope and falls. Continued bed rest worsens deconditioning. Supine-only exercises do not address orthostatic intolerance. The mobilization speed depends on patient response.", difficulty: 2, category: "Clinical Prioritization & Workflow", topic: "ICU Progressive Mobilization" },
  { id: "pta-b27-019", stem: "A PTA is measuring joint ROM using a goniometer. The measurement error that occurs most commonly with goniometric measurement is:", options: ["Inconsistent identification of bony landmarks and axis placement, which can be minimized by using standardized landmarks and taking the average of multiple measurements", "Error from the goniometer mechanism itself", "Error from patient dehydration", "Error from ambient room temperature"], correctIndex: 0, rationale: "The primary source of goniometric measurement error is the clinician, not the instrument. Inconsistent landmark identification and axis placement account for the majority of measurement variability. Strategies to minimize error: use standardized bony landmarks for each joint measurement, maintain consistent patient positioning, use the same goniometer, take multiple measurements and average them, and have the same clinician perform serial measurements when possible (intrarater reliability is higher than interrater reliability). Goniometer instruments are mechanically simple and rarely malfunction. Patient hydration and room temperature have negligible effects on measurement accuracy. Standardized measurement protocols are essential for reliable outcome tracking.", difficulty: 1, category: "Data Collection & Measurement", topic: "Goniometric Measurement Error" },
  { id: "pta-b27-020", stem: "A PTA is providing patient education about the use of a TENS unit at home. The patient should be instructed to:", options: ["Place electrodes on clean, intact skin around the painful area, adjust intensity to a comfortable tingling sensation, use for 30-60 minutes per session, and never place electrodes over the carotid sinus, eyes, or anterior neck", "Place electrodes directly on open wounds", "Use maximum intensity until pain is felt from the electrical stimulation", "Apply the TENS unit while bathing or showering"], correctIndex: 0, rationale: "Home TENS education: clean intact skin ensures good electrode contact and prevents infection. Electrodes placed around (not directly on) the painful area stimulate sensory nerves for pain modulation. Comfortable tingling intensity activates A-beta fibers (gate control theory) without causing pain. 30-60 minute sessions are typical. Contraindicated locations: carotid sinus (bradycardia/syncope risk), eyes, anterior neck (laryngospasm risk), and over the heart in patients with pacemakers. Open wounds: infection risk and uneven current distribution. Pain from TENS indicates excessive intensity. Water and electricity: electrocution risk. The PTA should have the patient demonstrate proper application before independent home use.", difficulty: 1, category: "Patient Education & Home Programs", topic: "Home TENS Use Education" },
  { id: "pta-b27-021", stem: "A PTA is measuring a patient's vital signs before exercise. The patient's resting blood pressure is 168/96 mmHg. According to current guidelines, the PTA should:", options: ["Hold exercise, notify the supervising PT of the elevated blood pressure, recheck in 5 minutes with proper technique, and await clearance before initiating exercise", "Begin high-intensity exercise immediately", "Ignore the blood pressure and proceed with the planned treatment", "Perform only passive stretching at this blood pressure"], correctIndex: 0, rationale: "Resting blood pressure of 168/96 mmHg is Stage 2 hypertension (SBP ≥140 or DBP ≥90). Exercise guidelines generally recommend holding vigorous exercise when resting SBP >180 or DBP >110, but significantly elevated BP at 168/96 warrants caution: hold exercise, recheck BP after 5 minutes of rest using proper technique (correct cuff size, supported arm, feet flat), notify the supervising PT, and await clearance. Factors that may temporarily elevate BP: recent caffeine, anxiety (white coat effect), recent activity, or improper measurement technique. Beginning high-intensity exercise with significantly elevated BP increases cardiovascular risk. Ignoring elevated BP violates patient safety principles. The PTA should establish baseline vitals and exercise parameters with the supervising PT.", difficulty: 1, category: "Patient Safety & Body Mechanics", topic: "Hypertension Exercise Hold" },
  { id: "pta-b27-022", stem: "A PTA is treating a patient 4 weeks post-Achilles tendon rupture repair. The patient is in a walking boot with 2 cm heel lift. Which exercise is appropriate at this stage?", options: ["Gentle active ankle plantarflexion within the boot, isometric calf contractions, and toe curling exercises to begin activating the calf-Achilles complex without placing tensile load on the repair", "Full-range passive ankle dorsiflexion stretching past neutral", "Resisted single-leg calf raises at body weight", "Plyometric jumping exercises"], correctIndex: 0, rationale: "At 4 weeks post-Achilles repair, the tendon has sufficient healing for gentle activation but not aggressive loading. Gentle active plantarflexion within the protected range of the boot initiates muscle activation without excessive tendon stress. Isometric contractions provide low-level loading. Toe curling activates the intrinsic foot muscles. Full dorsiflexion stretching past neutral places dangerous tensile load on the repair (risk of re-rupture or elongation). Single-leg calf raises generate peak loads exceeding repair strength at 4 weeks. Plyometric exercises create the highest Achilles loads and are not appropriate until 6+ months. The heel lift in the boot keeps the tendon in a shortened position, reducing tension on the repair site.", difficulty: 2, category: "Musculoskeletal Rehabilitation", topic: "Early Achilles Repair Exercises" },
  { id: "pta-b27-023", stem: "A PTA is performing spinal stabilization exercises with a patient who has chronic low back pain. The patient is instructed to perform the 'bird dog' exercise. The proper technique is:", options: ["In quadruped, simultaneously extend one arm and the opposite leg while maintaining a neutral spine and activating the deep stabilizers (transversus abdominis and multifidus)", "Lying supine and lifting all four extremities simultaneously", "In quadruped, extending both arms and both legs simultaneously", "Standing on one leg with eyes closed"], correctIndex: 0, rationale: "The bird dog exercise (quadruped opposite arm-leg extension) targets spinal stabilization through: transversus abdominis and multifidus activation (deep stabilizers maintaining neutral spine), contralateral arm-leg pattern (challenges rotational stability), and progressive loading (gravity creates extension and rotation demands). The patient must maintain neutral spine without sagging, rotating, or lateral shifting. Supine with all limbs raised is a different exercise. Extending all four limbs simultaneously in quadruped is impossible and dangerous. Standing single-leg balance is a different exercise category. The bird dog progresses from: simple arm extension → simple leg extension → contralateral arm-leg → adding perturbations. It is a core exercise in lumbar stabilization programs.", difficulty: 1, category: "Therapeutic Exercise", topic: "Bird Dog Stabilization Exercise" },
  { id: "pta-b27-024", stem: "A PTA is treating a patient with bilateral lower extremity peripheral arterial disease (PAD). The patient reports intermittent claudication (calf pain with walking that resolves with rest). The MOST effective exercise intervention is:", options: ["Supervised walking program: walk until near-maximal claudication pain, rest until pain subsides, then repeat for a total of 30-60 minutes, 3-5 times per week", "Complete avoidance of walking since it causes pain", "Only upper body exercises with no walking component", "Continuous walking without rest breaks despite severe pain"], correctIndex: 0, rationale: "Supervised walking programs for PAD are the gold standard non-surgical treatment: walking to near-maximal claudication (3-4/5 on claudication scale), resting until pain subsides completely, then repeating the walk-rest cycle for 30-60 minutes total per session. This induces ischemic preconditioning, promotes collateral vessel development (angiogenesis), improves endothelial function, and increases pain-free walking distance by 100-150%. Avoiding walking prevents the vascular adaptations needed. Upper body only misses the specific vascular bed that needs training. Continuous walking through severe pain may indicate critical ischemia requiring medical evaluation. The program is typically conducted for 12 weeks with progressive increases in walking duration.", difficulty: 2, category: "Cardiopulmonary Physical Therapy", topic: "PAD Claudication Walking Program" },
  { id: "pta-b27-025", stem: "A PTA observes that a colleague is treating a patient using a technique that the PTA believes may harm the patient. The PTA's ethical obligation is to:", options: ["Address the concern directly with the colleague first, and if the issue is not resolved, report the concern to the supervising PT or appropriate authority to ensure patient safety", "Ignore the concern to avoid conflict with the colleague", "Immediately report the colleague to the state licensing board without first discussing the concern", "Post about the concern on social media to warn the public"], correctIndex: 0, rationale: "Professional ethics require PTAs to prioritize patient safety. The appropriate chain of action: first address the concern directly with the colleague (may be a misunderstanding or knowledge gap that can be resolved collegially), if unresolved, escalate to the supervising PT or clinic manager, and if still unresolved, report to the appropriate authority (facility compliance, state licensing board). Ignoring the concern violates the ethical duty to protect patients. Skipping direct communication goes against professional courtesy and may be disproportionate. Social media posting violates patient confidentiality (HIPAA) and professional standards. The APTA Code of Ethics and state practice acts guide professional conduct.", difficulty: 1, category: "Ethics & Professional Practice", topic: "Patient Safety Ethical Obligation" },
  { id: "pta-b27-026", stem: "A PTA is treating a patient with a Wagner Grade 2 diabetic foot ulcer on the plantar surface of the first metatarsal head. The wound bed appears pink-red with granulation tissue. Which wound care intervention is MOST appropriate?", options: ["Maintain a moist wound environment with appropriate dressing, ensure total contact casting or offloading device, and monitor for signs of infection", "Allow the wound to air dry completely", "Apply hydrogen peroxide to the wound bed daily", "Pack the wound tightly with dry gauze"], correctIndex: 0, rationale: "Wagner Grade 2 diabetic foot ulcer (deeper ulcer involving tendon, bone, or joint capsule) with healthy granulation tissue requires: moist wound healing (evidence-based; promotes epithelial cell migration, reduces pain, and optimizes healing), offloading (total contact casting or therapeutic shoe to reduce repetitive trauma at the metatarsal head), and infection monitoring (diabetic patients have impaired immune response). Air drying delays healing and promotes scab formation that impedes epithelialization. Hydrogen peroxide is cytotoxic to granulation tissue and delays healing. Tightly packed dry gauze desiccates the wound bed and traumatizes tissue upon removal. Moist wound healing is the current standard of care.", difficulty: 2, category: "Integumentary & Wound Care", topic: "Diabetic Foot Ulcer Care" },
  { id: "pta-b27-027", stem: "A PTA is providing gait training to a patient who uses a single-point cane. The patient has weakness in the RIGHT lower extremity. When ascending stairs, the correct sequence is:", options: ["Left (stronger) leg up first, then right leg and cane together, following the mnemonic 'up with the good'", "Right (weaker) leg up first", "Cane up first, then both legs together", "No specific sequence is recommended"], correctIndex: 0, rationale: "Stair climbing with a cane follows the mnemonic: 'Up with the good, down with the bad.' Ascending: the stronger (left) leg steps up first (uses the strong leg to lift body weight against gravity), then the weaker (right) leg and cane come up together to the same step. Descending is reversed: cane and weaker leg step down first (stronger leg controls the eccentric lowering), then the stronger leg follows. Leading with the weaker leg going upstairs means the weak leg must lift body weight, which it cannot do safely. The specific sequence maximizes safety and energy efficiency. This applies to canes, crutches, and walkers on stairs.", difficulty: 1, category: "Gait Training & Assistive Devices", topic: "Cane Stair Ascending Sequence" },
  { id: "pta-b27-028", stem: "A PTA is treating a 3-year-old child with torticollis. The child holds the head tilted to the RIGHT with the chin rotated to the LEFT. This indicates shortening of which muscle?", options: ["Right sternocleidomastoid (SCM), which when shortened causes ipsilateral lateral flexion and contralateral rotation", "Left sternocleidomastoid", "Right upper trapezius only", "Bilateral scalene muscles"], correctIndex: 0, rationale: "The sternocleidomastoid muscle produces ipsilateral lateral flexion (ear toward same shoulder) and contralateral rotation (chin toward opposite shoulder). A shortened RIGHT SCM causes: head tilted to the RIGHT (ipsilateral lateral flexion) and chin rotated to the LEFT (contralateral rotation). Treatment: stretching the right SCM (lateral flexion to the left and rotation to the right), strengthening the left SCM, positioning strategies (encouraging the child to look toward the right to actively stretch the right SCM), and tummy time for neck strengthening. The left SCM would cause left tilt with right chin rotation. Upper trapezius causes ipsilateral lateral flexion but not contralateral rotation. Bilateral scalene involvement would cause bilateral symptoms.", difficulty: 2, category: "Pediatric Rehabilitation", topic: "Torticollis SCM Identification" },
  { id: "pta-b27-029", stem: "A PTA is developing a fall prevention exercise program for community-dwelling older adults. Based on current evidence, the program MUST include:", options: ["Balance-challenging exercises performed at least 3 hours per week, progressive in difficulty, and including tai chi or specific balance training as the primary component", "Only upper body strengthening", "Only cardiovascular fitness training on a recumbent bike", "Flexibility exercises only without balance challenge"], correctIndex: 0, rationale: "Evidence-based fall prevention exercise: balance-challenging exercises are the essential component (exercises that challenge the center of mass relative to the base of support). Current guidelines recommend at least 3 hours/week of balance training, with progressive difficulty (reducing base of support, removing visual input, adding cognitive dual-tasks). Tai chi has the strongest evidence for fall reduction in older adults (reduces falls by 19-43%). Upper body strengthening alone does not challenge balance. Cardiovascular training without balance work does not reduce falls. Flexibility without balance challenge is insufficient. Effective programs challenge balance, include progressive overload, and are sustained over time.", difficulty: 2, category: "Geriatric Rehabilitation", topic: "Evidence-Based Fall Prevention" },
  { id: "pta-b27-030", stem: "A PTA is treating a patient with cervicogenic dizziness. The patient reports dizziness with cervical rotation. After ruling out BPPV, the PTA should focus treatment on:", options: ["Cervical ROM exercises, cervical joint mobilization as delegated by the PT, oculomotor exercises, and proprioceptive retraining to address the cervical contribution to dizziness", "Only vestibular exercises (canalith repositioning maneuvers)", "Cervical traction at maximum weight", "Complete cervical immobilization with a rigid collar"], correctIndex: 0, rationale: "Cervicogenic dizziness results from abnormal cervical proprioceptive input to the vestibular system (not vestibular pathology). Treatment targets the cervical source: cervical ROM exercises restore normal joint mechanics, joint mobilization (within PT-delegated parameters) addresses restrictions, oculomotor exercises improve cervical-ocular coordination, and proprioceptive retraining normalizes afferent input. Canalith repositioning is for BPPV (already ruled out). Maximum cervical traction may worsen symptoms without addressing proprioception. Rigid collar immobilization reduces cervical proprioceptive input and promotes stiffness. The cervical spine provides significant proprioceptive input to the vestibular system via the cervico-collic and cervico-ocular reflexes.", difficulty: 3, category: "Neurological Rehabilitation", topic: "Cervicogenic Dizziness Treatment" },
  { id: "pta-b27-031", stem: "A PTA is evaluating the effectiveness of a patient's ankle-foot orthosis (AFO). The patient has foot drop due to peroneal nerve palsy. A properly functioning AFO should:", options: ["Prevent excessive plantarflexion during swing phase (foot drop) while allowing controlled dorsiflexion during stance, improving toe clearance and normalizing gait pattern", "Lock the ankle in maximum plantarflexion", "Increase the foot drop during gait", "Only provide support during non-weight-bearing activities"], correctIndex: 0, rationale: "An AFO for foot drop serves to: prevent excessive plantarflexion during swing phase (the primary problem of foot drop is inability to dorsiflex during swing, causing toe drag), allow controlled dorsiflexion during stance (normal heel rocker mechanism), and normalize the gait pattern. A posterior leaf spring AFO or hinged AFO provides this function. Locking in plantarflexion would worsen the problem. The AFO should improve, not increase, foot drop. AFOs provide primary benefit during weight-bearing gait, not non-weight-bearing activities. The PTA should assess gait with and without the AFO to evaluate effectiveness and monitor skin integrity under the orthosis.", difficulty: 1, category: "Prosthetics & Orthotics", topic: "AFO Foot Drop Effectiveness" },
  { id: "pta-b27-032", stem: "A PTA is treating a patient with bilateral carpal tunnel syndrome. Night splinting is recommended to maintain the wrist in:", options: ["Neutral position (0° extension), which minimizes carpal tunnel pressure and reduces nocturnal compression of the median nerve", "Maximum wrist flexion", "Maximum wrist extension", "Maximum ulnar deviation"], correctIndex: 0, rationale: "Carpal tunnel pressure is lowest with the wrist in neutral (0° extension). During sleep, the wrist often falls into flexion or extension, both of which increase carpal tunnel pressure and compress the median nerve (causing the nocturnal numbness and tingling characteristic of CTS). Night splints maintain the wrist in neutral, minimizing pressure and reducing symptoms. Maximum flexion (Phalen's position) maximally compresses the median nerve. Maximum extension also increases carpal tunnel pressure. Ulnar deviation does not address the wrist position issue. Night splinting is a first-line conservative treatment that can significantly reduce symptoms, especially the nocturnal paresthesias that are the hallmark of CTS.", difficulty: 1, category: "Musculoskeletal Rehabilitation", topic: "CTS Night Splinting Position" },
  { id: "pta-b27-033", stem: "A PTA is treating a patient with a recent below-knee amputation. The patient reports phantom limb pain (feeling pain in the amputated foot). Evidence-based interventions include:", options: ["Mirror therapy, desensitization of the residual limb, TENS application, graded motor imagery, and early prosthetic fitting", "Ignoring the pain since the limb no longer exists", "Only pharmacological management with no physical therapy", "Re-amputation at a higher level to eliminate phantom pain"], correctIndex: 0, rationale: "Phantom limb pain (PLP) is a real neurological phenomenon caused by cortical reorganization and peripheral neural changes. Evidence-based interventions: mirror therapy (visual feedback normalizes cortical representation), desensitization (reduces neuroma sensitivity and normalizes sensory processing), TENS (modulates pain transmission), graded motor imagery (progressive mental and visual practice), and early prosthetic fitting (provides proprioceptive input that reduces cortical reorganization). PLP is not imaginary; ignoring it is medically inappropriate. Pharmacological management alone is insufficient. Higher-level amputation does not eliminate PLP and sacrifices more functional tissue. Physical therapy plays a significant role in PLP management.", difficulty: 2, category: "Pain Management", topic: "Phantom Limb Pain Interventions" },
  { id: "pta-b27-034", stem: "A PTA is performing a manual muscle test on the gluteus maximus. The correct test position for a Grade 3 (Fair) test is:", options: ["Prone with the knee flexed to 90°, the patient extends the hip against gravity through the full available range without additional resistance", "Sidelying with the hip extended against gravity", "Supine with hip extension against resistance", "Seated with hip flexion against gravity"], correctIndex: 0, rationale: "Gluteus maximus MMT for Grade 3 (Fair): patient prone (gravity-resisted position for hip extension), knee flexed to 90° (reduces hamstring contribution, isolating the gluteus maximus), patient extends the hip through full ROM against gravity without external resistance. Grade 3 = full ROM against gravity, no resistance. Knee flexion during testing is key because the hamstrings are placed in a shortened position, reducing their effectiveness as hip extensors. Sidelying is a gravity-eliminated position for hip extension (Grade 2 testing). Supine hip extension is not a standard test position. Seated hip flexion tests hip flexors (iliopsoas), not extensors.", difficulty: 2, category: "Data Collection & Measurement", topic: "Gluteus Maximus MMT Position" },
  { id: "pta-b27-035", stem: "A PTA is working with a patient on a blood thinner (rivaroxaban/Xarelto). The patient falls during gait training and hits their head on the mat table. There is no visible injury, and the patient reports feeling fine. The PTA should:", options: ["Report the incident immediately to the supervising PT and physician, document the fall thoroughly, and monitor the patient closely for signs of intracranial bleeding due to the anticoagulant medication", "Send the patient home since they feel fine", "Continue the therapy session as planned", "Only document the fall at the end of the day"], correctIndex: 0, rationale: "Head trauma in a patient on anticoagulant medication (rivaroxaban is a direct oral anticoagulant) requires immediate medical evaluation regardless of current symptoms. Anticoagulants increase the risk and severity of intracranial bleeding, which may not present symptoms until hours after the trauma. The PTA must: immediately report to the supervising PT and physician, complete a detailed incident report (time, mechanism, vital signs, symptoms), and closely monitor for signs of intracranial bleeding (headache, confusion, nausea, unequal pupils, drowsiness). Sending the patient home without evaluation is dangerous. Continuing therapy without addressing the fall is negligent. Delayed documentation violates incident reporting standards.", difficulty: 2, category: "Patient Safety & Body Mechanics", topic: "Fall Head Injury Anticoagulant" },
  { id: "pta-b27-036", stem: "A PTA is educating a patient about proper posture during prolonged sitting at a desk. The lumbar spine should be maintained in:", options: ["A slight lordotic curve (natural lumbar curve) using a lumbar support roll or chair with built-in lumbar support to reduce intradiscal pressure", "Maximum flexion (rounded forward) for comfort", "Maximum extension with rigid bracing", "A completely flat position against the chair back"], correctIndex: 0, rationale: "Optimal seated lumbar posture: maintain the natural lordotic curve (slight extension). Research shows intradiscal pressure is lowest in supported sitting with lumbar lordosis. A lumbar support roll at the L3-L5 level maintains this curve. Maximum flexion (slumped posture) increases intradiscal pressure by 40-90% compared to standing and stretches posterior ligaments. Maximum extension with bracing is unnecessarily rigid and uncomfortable. A completely flat lumbar spine eliminates the natural curve and increases disc loading. Additional ergonomic principles: feet flat on floor, thighs parallel to floor, monitor at eye level, forearms supported at 90° elbow flexion.", difficulty: 1, category: "Patient Education & Home Programs", topic: "Seated Lumbar Posture" },
  { id: "pta-b27-037", stem: "A PTA is providing education about falls prevention to a geriatric patient. Which medication category is MOST strongly associated with increased fall risk?", options: ["Psychotropic medications (benzodiazepines, antidepressants, antipsychotics) due to their sedative effects, impaired balance, and orthostatic hypotension side effects", "Multivitamins", "Acetaminophen (Tylenol)", "Topical anti-itch cream"], correctIndex: 0, rationale: "Psychotropic medications are the medication class most strongly associated with falls in older adults. Benzodiazepines (diazepam, lorazepam) cause sedation, impaired balance, and delayed reaction time. Antidepressants (SSRIs, tricyclics) cause orthostatic hypotension and dizziness. Antipsychotics cause sedation, extrapyramidal effects, and orthostatic hypotension. Other high-risk medications include opioids, antihypertensives, and anticholinergics. Multivitamins, acetaminophen, and topical creams do not significantly increase fall risk. The PTA should review the medication list for fall-risk medications and communicate concerns about polypharmacy to the healthcare team. Medication review and reduction is a key component of multifactorial fall prevention.", difficulty: 2, category: "Pharmacology for PTAs", topic: "Fall Risk Medications" },
  { id: "pta-b27-038", stem: "A PTA is performing a wound assessment and notes the wound bed is covered with thick, black, leathery tissue. This tissue is classified as:", options: ["Eschar (necrotic tissue) that must be removed through debridement before the wound stage/depth can be accurately assessed and healing can progress", "Healthy granulation tissue indicating wound healing", "Normal skin that should not be disturbed", "Scar tissue indicating wound closure"], correctIndex: 0, rationale: "Eschar is thick, black/brown, leathery necrotic tissue that adheres to the wound bed. It prevents wound assessment (cannot stage the wound until eschar is removed), impedes healing by acting as a barrier to granulation tissue formation, and provides a medium for bacterial growth. Debridement (sharp, enzymatic, autolytic, or mechanical) is required before healing can progress. Healthy granulation tissue is pink-red and moist. Eschar is not normal skin. Scar tissue (mature wound closure) is typically pale and flat, not black and leathery. The exception to debridement: stable, dry eschar on the heel may be left intact as a biological cover if there are no signs of infection, because the heel has limited blood supply for wound healing.", difficulty: 1, category: "Integumentary & Wound Care", topic: "Eschar Identification" },
  { id: "pta-b27-039", stem: "A PTA is providing a patient with instructions for performing the Brandt-Daroff exercises at home for BPPV. The correct technique involves:", options: ["Sitting at the edge of the bed, rapidly lying to one side with the head turned 45° upward, holding for 30 seconds or until dizziness subsides, sitting up, then repeating on the opposite side", "Slowly standing and sitting 10 times", "Lying supine and turning the head side to side rapidly for 5 minutes", "Walking in circles for 10 minutes"], correctIndex: 0, rationale: "Brandt-Daroff exercises are a home habituation treatment for BPPV: start seated at bed edge, rapidly lie to one side with head turned 45° upward (targets the semicircular canal), hold 30 seconds or until dizziness resolves, return to sitting (hold 30 seconds), then repeat on the opposite side. Perform 5 repetitions per side, 3 times daily. The exercises work through habituation (gradual reduction in vestibular response to repeated stimulation) and may also help disperse otoconia. Standing and sitting is not a vestibular exercise. Rapid supine head turning is not the correct Brandt-Daroff technique. Walking in circles does not target the semicircular canals. The exercises are adjunctive to the Epley maneuver performed by the clinician.", difficulty: 2, category: "Neurological Rehabilitation", topic: "Brandt-Daroff Home Exercise" },
  { id: "pta-b27-040", stem: "A patient with a long-standing L5-S1 disc herniation presents with progressive foot drop and saddle anesthesia (numbness in the perineal area). The PTA should:", options: ["Stop treatment immediately, notify the supervising PT and referring physician urgently, as saddle anesthesia with progressive neurological deficit is a red flag for cauda equina syndrome requiring emergency surgical evaluation", "Continue with planned lumbar stabilization exercises", "Apply hot packs to the low back and schedule a follow-up in 2 weeks", "Increase traction weight to decompress the disc further"], correctIndex: 0, rationale: "Saddle anesthesia (perineal numbness) combined with progressive neurological deficit (foot drop) are cardinal signs of cauda equina syndrome (CES), a surgical emergency. CES involves compression of the nerve roots in the lumbar spinal canal, potentially causing permanent bowel/bladder dysfunction, sexual dysfunction, and lower extremity paralysis if not decompressed within 24-48 hours. Other red flags: bowel/bladder incontinence or retention, bilateral leg weakness. The PTA must immediately stop treatment and urgently communicate with the PT and physician. Continuing exercises, applying modalities, or scheduling routine follow-up delays emergency intervention. This is a time-sensitive emergency where delayed recognition causes permanent disability.", difficulty: 3, category: "Clinical Prioritization & Workflow", topic: "Cauda Equina Syndrome Red Flags" }
];
